interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface ClaimStep {
  op: "claim";
  policy: number;
  incident: {
    cause: string;
    damages: { itemType: string; amount: number }[];
  };
}

type Step = QuoteStep | ClaimStep;

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

interface QuoteResult {
  premium: number;
}

interface ClaimResult {
  payout: number;
  remainingCap: number;
}

interface ScenarioResult {
  results: (QuoteResult | ClaimResult)[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE_PREMIUM = 25;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
const PROCESSING_FEE = 5;

function ceilPercent(amount: number, percent: number): number {
  return Math.ceil(amount * percent / 100);
}

export function processScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => {
    const quoteStep = step as QuoteStep;
    let premium = 0;
    for (const item of quoteStep.items) {
      premium += BASE_PREMIUMS[item.type] ?? COMPONENT_BASE_PREMIUM;
    }
    premium += ceilPercent(premium, FIRST_INSURANCE_SURCHARGE_PERCENT);
    premium += PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

