import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it("should calculate base premium for a single sword plus processing fee", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // Sword base premium: 100G
      // First insurance surcharge: 10% -> 100 * 1.10 = 110G
      // Processing fee: 5G
      // Total: 115G
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("should calculate base premium for each main item type (amulet, staff, potion)", () => {
      // Amulet: 60G base, first insurance +10% = 66G + 5G fee = 71G
      const amuletResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(amuletResult.results[0]).toEqual({ premium: 71 });

      // Staff: 80G base, first insurance +10% = 88G + 5G fee = 93G
      const staffResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "wood", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(staffResult.results[0]).toEqual({ premium: 93 });

      // Potion: 40G base, first insurance +10% = 44G + 5G fee = 49G
      const potionResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(potionResult.results[0]).toEqual({ premium: 49 });
    });
    it("should calculate base premium for a single component", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // Component (rune) base premium: 25G
      // First insurance surcharge: 10% -> ceil(25 * 10 / 100) = ceil(2.5) = 3G
      // Premium so far: 28G
      // Processing fee: 5G
      // Total: 33G
      expect(result.results[0]).toEqual({ premium: 33 });
    });
    it("should apply building block premium for 3 alike components", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // 3 alike components = building block: 60G special premium (not 3 × 25 = 75G)
      // First insurance surcharge: 10% -> ceil(60 * 10 / 100) = 6G
      // Premium so far: 66G
      // Processing fee: 5G
      // Total: 71G
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it("should combine premiums for multiple items", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // Sword: 100G + Amulet: 60G = 160G base
      // First insurance surcharge: ceil(160 * 10 / 100) = 16G
      // Premium: 176G + 5G fee = 181G
      expect(result.results[0]).toEqual({ premium: 181 });
    });
    it("should add 50% surcharge for cursed items", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: true },
            ],
          },
        ],
      });
      // Sword base: 100G
      // Cursed surcharge: 50% -> ceil(100 * 50 / 100) = 50G
      // Item premium: 150G
      // First insurance surcharge: ceil(150 * 10 / 100) = 15G
      // Premium: 165G + 5G fee = 170G
      expect(result.results[0]).toEqual({ premium: 170 });
    });
    it("should add 30% surcharge for highly enchanted items (enchantment >= 5)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "wood", enchantment: 5, cursed: false },
            ],
          },
        ],
      });
      // Staff base: 80G
      // Enchantment surcharge (level >= 5): 30% -> ceil(80 * 30 / 100) = 24G
      // Item premium: 104G
      // First insurance surcharge: ceil(104 * 10 / 100) = ceil(10.4) = 11G
      // Premium: 115G + 5G fee = 120G
      expect(result.results[0]).toEqual({ premium: 120 });
    });
    it("should apply both cursed and enchantment surcharges when both apply", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 6, cursed: true },
            ],
          },
        ],
      });
      // Amulet base: 60G
      // Cursed surcharge: ceil(60 * 50 / 100) = 30G -> 90G
      // Enchantment surcharge (level 6 >= 5): ceil(90 * 30 / 100) = 27G -> 117G
      // First insurance surcharge: ceil(117 * 10 / 100) = ceil(11.7) = 12G -> 129G
      // Processing fee: 5G
      // Total: 134G
      expect(result.results[0]).toEqual({ premium: 134 });
    });
    it("should apply 20% loyalty discount for long-standing customers (>= 2 years)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 3 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // Sword base: 100G
      // First insurance surcharge: ceil(100 * 10 / 100) = 10G -> 110G
      // Loyalty discount (>= 2 years): floor(110 * 20 / 100) = 22G -> 88G
      // Processing fee: 5G
      // Total: 93G
      expect(result.results[0]).toEqual({ premium: 93 });
    });
    it("should apply 10% initial assessment surcharge for first insurance", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // First quote (potion): 40G base + ceil(40*10/100)=4G surcharge = 44G + 5G = 49G
      expect(result.results[0]).toEqual({ premium: 49 });
      // Second quote (sword): NO first insurance surcharge -> 100G base + 5G = 105G
      expect(result.results[1]).toEqual({ premium: 105 });
    });
    it.todo("should apply 15% discount on contracts after the first");
    it.todo("should round amounts in MHPCO's favor");
  });

  describe("Processing a claim", () => {
    it.todo("should apply 100G deductible per damage event");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse at 50% for items with enchantment level >= 8");
    it.todo("should fully reimburse damage to items made of dragon material");
    it.todo("should track remaining cap across multiple claims on the same policy");
  });

  describe("CLI integration", () => {
    it.todo("should process a quote step and return premium");
    it.todo("should process a quote followed by a claim and return both results");
  });
});

interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface ClaimStep {
  op: "claim";
  policy: number;
  incident: {
    cause: string;
    damages: { itemType: string; amount: number }[];
  };
}

type Step = QuoteStep | ClaimStep;

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

interface QuoteResult {
  premium: number;
}

interface ClaimResult {
  payout: number;
  remainingCap: number;
}

interface ScenarioResult {
  results: (QuoteResult | ClaimResult)[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE_PREMIUM = 25;
const BUILDING_BLOCK_PREMIUM = 60;
const BUILDING_BLOCK_SIZE = 3;
const CURSED_SURCHARGE_PERCENT = 50;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
const LOYALTY_THRESHOLD_YEARS = 2;
const LOYALTY_DISCOUNT_PERCENT = 20;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
const PROCESSING_FEE = 5;

function ceilPercent(amount: number, percent: number): number {
  return Math.ceil(amount * percent / 100);
}

function floorPercent(amount: number, percent: number): number {
  return Math.floor(amount * percent / 100);
}

function calculateQuotePremium(items: Item[], customer: { yearsWithMHPCO: number }): number {
  let premium = 0;
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (item.type in BASE_PREMIUMS) {
      let itemPremium = BASE_PREMIUMS[item.type];
      if (item.cursed) {
        itemPremium += ceilPercent(itemPremium, CURSED_SURCHARGE_PERCENT);
      }
      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
        itemPremium += ceilPercent(itemPremium, HIGH_ENCHANTMENT_SURCHARGE_PERCENT);
      }
      premium += itemPremium;
    } else {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    }
  }
  for (const count of Object.values(componentCounts)) {
    const blocks = Math.floor(count / BUILDING_BLOCK_SIZE);
    const remainder = count % BUILDING_BLOCK_SIZE;
    premium += blocks * BUILDING_BLOCK_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;
  }
  premium += ceilPercent(premium, FIRST_INSURANCE_SURCHARGE_PERCENT);
  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
    premium -= floorPercent(premium, LOYALTY_DISCOUNT_PERCENT);
  }
  premium += PROCESSING_FEE;
  return premium;
}

export function processScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => {
    const quoteStep = step as QuoteStep;
    return { premium: calculateQuotePremium(quoteStep.items, scenario.customer) };
  });
  return { results };
}

