      results.push({
        premium: calculateQuotePremium(step.items, scenario.customer, i === 0),
      });
    } else {
      const policyStep = scenario.steps[step.policy] as QuoteStep;
      results.push(calculateClaimPayout(step, policyStep.items));
    }
  }
  return { results };
}

